import{_ as n,o as a,c as o,a2 as l}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"API Keys and Config","description":"Securely manage API keys and application configuration without hardcoding secrets in source code.","frontmatter":{"title":"API Keys and Config","description":"Securely manage API keys and application configuration without hardcoding secrets in source code."},"headers":[],"relativePath":"learn/project/02-first-llm-call/03-api-keys-and-config.md","filePath":"learn/project/02-first-llm-call/03-api-keys-and-config.md"}'),e={name:"learn/project/02-first-llm-call/03-api-keys-and-config.md"};function p(t,s,c,r,i,y){return a(),o("div",null,[...s[0]||(s[0]=[l(`<h1 id="api-keys-and-config" tabindex="-1">API Keys and Config <a class="header-anchor" href="#api-keys-and-config" aria-label="Permalink to &quot;API Keys and Config&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>Why API keys must never be committed to version control and how to prevent accidental exposure</li><li>How to load configuration from environment variables, dotenv files, and config files in priority order</li><li>How to structure a Config struct that centralizes all runtime configuration for your agent</li></ul></blockquote><p>Before you write a single line of HTTP code, you need to handle the most sensitive piece of the puzzle: your API key. Getting this wrong can be expensive -- literally. A leaked API key can be scraped by bots and used to rack up charges on your account. This subchapter shows you the right way to manage secrets in a Rust project.</p><h2 id="getting-your-api-key" tabindex="-1">Getting Your API Key <a class="header-anchor" href="#getting-your-api-key" aria-label="Permalink to &quot;Getting Your API Key&quot;">​</a></h2><p>First, you need an Anthropic API key. Head to <a href="https://console.anthropic.com" target="_blank" rel="noreferrer">console.anthropic.com</a>, create an account if you have not already, and navigate to the API Keys section. Click &quot;Create Key&quot;, give it a name like &quot;cli-agent-dev&quot;, and copy the key. It looks something like this:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>sk-ant-api03-xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx</span></span></code></pre></div><p>This key is shown <strong>exactly once</strong>. If you lose it, you will need to create a new one. Copy it somewhere safe right now -- you will use it in a moment.</p><h2 id="the-cardinal-rule-never-hardcode-secrets" tabindex="-1">The Cardinal Rule: Never Hardcode Secrets <a class="header-anchor" href="#the-cardinal-rule-never-hardcode-secrets" aria-label="Permalink to &quot;The Cardinal Rule: Never Hardcode Secrets&quot;">​</a></h2><p>This might seem obvious, but it is worth stating explicitly: <strong>never put your API key directly in your source code.</strong> Not even temporarily. Not even in a &quot;test file.&quot; Here is what NOT to do:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// DO NOT DO THIS -- this key will end up in version control</span></span>
<span class="line"><span style="color:#CBA6F7;">const</span><span style="color:#FAB387;"> API_KEY</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#94E2D5;"> =</span><span style="color:#A6E3A1;"> &quot;sk-ant-api03-real-key-here&quot;</span><span style="color:#9399B2;">;</span></span></code></pre></div><p>The moment you commit that file and push it to a public (or even private) repository, your key is compromised. GitHub actively scans for API key patterns and will notify Anthropic, who may revoke the key, but the window of exposure is still dangerous.</p><p>Instead, you will load the key from the environment at runtime.</p><h2 id="environment-variables-the-standard-approach" tabindex="-1">Environment Variables: The Standard Approach <a class="header-anchor" href="#environment-variables-the-standard-approach" aria-label="Permalink to &quot;Environment Variables: The Standard Approach&quot;">​</a></h2><p>The most common way to pass secrets to a program is through environment variables. You set them in your shell before running your program:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">export</span><span style="color:#CDD6F4;"> ANTHROPIC_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;sk-ant-api03-xxxxx&quot;</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">cargo</span><span style="color:#A6E3A1;"> run</span></span></code></pre></div><p>Inside your Rust code, you read them with <code>std::env::var</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">env</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> api_key </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY must be set&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Key loaded: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">...</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">api_key</span><span style="color:#9399B2;">[</span><span style="color:#94E2D5;">..</span><span style="color:#FAB387;">10</span><span style="color:#9399B2;">],</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CDD6F4;">api_key</span><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">api_key</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">-</span><span style="color:#FAB387;">4</span><span style="color:#94E2D5;">..</span><span style="color:#9399B2;">]);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This program reads the <code>ANTHROPIC_API_KEY</code> environment variable. If it is not set, <code>env::var</code> returns <code>Err</code>, and <code>expect</code> panics with a descriptive message. If it is set, you get the key as a <code>String</code>.</p><p>The <code>println!</code> only shows the first 10 and last 4 characters of the key -- never log a full API key, even during development.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>In Python, you would use <code>os.environ</code> or <code>os.getenv</code>:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> os</span></span>
<span class="line"><span style="color:#CDD6F4;">api_key </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> os</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">environ</span><span style="color:#9399B2;">[</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#A6E3A1;font-style:italic;">ANTHROPIC_API_KEY</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">]</span><span style="color:#6C7086;font-style:italic;">  # Raises KeyError if missing</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># or</span></span>
<span class="line"><span style="color:#CDD6F4;">api_key </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> os</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">getenv</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">   # Returns None if missing</span></span></code></pre></div><p>Rust&#39;s <code>env::var</code> is equivalent to <code>os.environ.get()</code> -- it returns a <code>Result</code> that you must handle explicitly. There is no silent <code>None</code> return. This forced error handling is exactly what you want for a required secret: you find out immediately at startup if the key is missing, not halfway through a conversation.</p></div><h2 id="dotenv-files-for-local-development" tabindex="-1">Dotenv Files for Local Development <a class="header-anchor" href="#dotenv-files-for-local-development" aria-label="Permalink to &quot;Dotenv Files for Local Development&quot;">​</a></h2><p>Typing <code>export ANTHROPIC_API_KEY=...</code> every time you open a new terminal gets old fast. The <code>dotenvy</code> crate (a maintained fork of the older <code>dotenv</code> crate) loads variables from a <code>.env</code> file into the process environment at startup.</p><p>First, add it to your <code>Cargo.toml</code>:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#9399B2;">[</span><span style="color:#CDD6F4;">dependencies</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CDD6F4;">dotenvy </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;0.15&quot;</span></span></code></pre></div><p>Create a <code>.env</code> file in your project root:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># .env -- local development secrets (DO NOT COMMIT)</span></span>
<span class="line"><span style="color:#CDD6F4;">ANTHROPIC_API_KEY</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">sk-ant-api03-xxxxx</span></span>
<span class="line"><span style="color:#CDD6F4;">ANTHROPIC_MODEL</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">claude-sonnet-4-20250514</span></span>
<span class="line"><span style="color:#CDD6F4;">MAX_TOKENS</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">4096</span></span></code></pre></div><p>Then load it early in your program:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">env</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Load .env file if it exists (silently ignore if missing)</span></span>
<span class="line"><span style="color:#F9E2AF;">    dotenvy</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">dotenv</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">ok</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> api_key </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY must be set&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;API key loaded successfully&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>dotenvy::dotenv().ok()</code> call reads the <code>.env</code> file and injects each line as an environment variable. The <code>.ok()</code> discards any error (like the file not existing), which is the right behavior -- in production, you set environment variables directly and do not use a <code>.env</code> file.</p><p><strong>Critical:</strong> Add <code>.env</code> to your <code>.gitignore</code> immediately:</p><div class="language-gitignore"><button title="Copy Code" class="copy"></button><span class="lang">gitignore</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span># .gitignore</span></span>
<span class="line"><span>.env</span></span>
<span class="line"><span>target/</span></span></code></pre></div><p>This prevents accidental commits of your secrets.</p><h2 id="building-a-config-struct" tabindex="-1">Building a Config Struct <a class="header-anchor" href="#building-a-config-struct" aria-label="Permalink to &quot;Building a Config Struct&quot;">​</a></h2><p>As your agent grows, you will need more than just an API key. Model name, max tokens, temperature, base URL -- these all belong together. A <code>Config</code> struct centralizes them:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">env</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Config</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> api_key</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> model</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> max_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> api_base_url</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> Config</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> from_env</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F38BA8;">Self</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> api_key </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">map_err</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">_</span><span style="color:#94E2D5;">|</span><span style="color:#A6E3A1;"> &quot;ANTHROPIC_API_KEY environment variable is not set. \\</span></span>
<span class="line"><span style="color:#A6E3A1;">                          Get your key at https://console.anthropic.com&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">())</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> model </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_MODEL&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">_</span><span style="color:#94E2D5;">|</span><span style="color:#A6E3A1;"> &quot;claude-sonnet-4-20250514&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">());</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> max_tokens </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;MAX_TOKENS&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">_</span><span style="color:#94E2D5;">|</span><span style="color:#A6E3A1;"> &quot;4096&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">())</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">parse</span><span style="color:#94E2D5;">::</span><span style="color:#89DCEB;">&lt;</span><span style="color:#CBA6F7;">u32</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">map_err</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">e</span><span style="color:#94E2D5;">|</span><span style="color:#89B4FA;font-style:italic;"> format!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;MAX_TOKENS must be a valid integer: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">e</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">))</span><span style="color:#94E2D5;">?</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> api_base_url </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;"> env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_BASE_URL&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">_</span><span style="color:#94E2D5;">|</span><span style="color:#A6E3A1;"> &quot;https://api.anthropic.com&quot;</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">());</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">        Ok</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Config</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">            api_key</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            model</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            max_tokens</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            api_base_url</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        })</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Notice the pattern here: required variables (like <code>api_key</code>) return an error if missing, while optional variables (like <code>model</code>) fall back to sensible defaults with <code>unwrap_or_else</code>. The <code>MAX_TOKENS</code> parsing demonstrates how to validate and convert string environment variables to the types you actually need.</p><p>Using this in <code>main</code>:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F9E2AF;">    dotenvy</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">dotenv</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">ok</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> config </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> Config</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_env</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or_else</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">e</span><span style="color:#94E2D5;">|</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">        eprintln!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Configuration error: </span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">e</span><span style="color:#9399B2;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#F9E2AF;">        std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">exit</span><span style="color:#9399B2;">(</span><span style="color:#FAB387;">1</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">    });</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Connecting to </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> with model </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> config</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">api_base_url</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> config</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">model</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The <code>unwrap_or_else</code> with <code>process::exit(1)</code> gives you a clean error message and a non-zero exit code, which is better than a panic backtrace for a configuration error.</p><h2 id="preventing-accidental-key-exposure" tabindex="-1">Preventing Accidental Key Exposure <a class="header-anchor" href="#preventing-accidental-key-exposure" aria-label="Permalink to &quot;Preventing Accidental Key Exposure&quot;">​</a></h2><p>Beyond <code>.gitignore</code>, here are additional safeguards:</p><p><strong>Git hooks.</strong> A pre-commit hook can scan staged files for patterns that look like API keys:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#F5C2E7;font-style:italic;">#!/bin/bash</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># .git/hooks/pre-commit</span></span>
<span class="line"><span style="color:#CBA6F7;">if</span><span style="color:#89B4FA;font-style:italic;"> git</span><span style="color:#A6E3A1;"> diff</span><span style="color:#A6E3A1;"> --cached</span><span style="color:#A6E3A1;"> --diff-filter=ACM</span><span style="color:#94E2D5;"> |</span><span style="color:#89B4FA;font-style:italic;"> grep</span><span style="color:#A6E3A1;"> -q</span><span style="color:#A6E3A1;"> &#39;sk-ant-api&#39;</span><span style="color:#9399B2;">;</span><span style="color:#CBA6F7;"> then</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    echo</span><span style="color:#A6E3A1;"> &quot;ERROR: Possible API key detected in staged changes!&quot;</span></span>
<span class="line"><span style="color:#F38BA8;font-style:italic;">    exit</span><span style="color:#FAB387;"> 1</span></span>
<span class="line"><span style="color:#CBA6F7;">fi</span></span></code></pre></div><p><strong>Implement <code>Debug</code> carefully.</strong> If you ever derive <code>Debug</code> on a struct containing secrets, the key will appear in debug output and logs. Override the <code>Debug</code> implementation to redact it:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">fmt</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> Config</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> api_key</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> model</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> max_tokens</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> u32</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CDD6F4;"> api_base_url</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;"> fmt</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#CBA6F7;"> for</span><span style="color:#F9E2AF;font-style:italic;"> Config</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> fmt</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> f</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F9E2AF;"> fmt</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Formatter</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">&#39;</span><span style="color:#89B4FA;font-style:italic;">_</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;"> fmt</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Result</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">        f</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">debug_struct</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;Config&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">field</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;api_key&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#A6E3A1;">&quot;[REDACTED]&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">field</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;model&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">model</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">field</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;max_tokens&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">max_tokens</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">field</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;api_base_url&quot;</span><span style="color:#9399B2;">,</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">api_base_url</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">            .</span><span style="color:#89B4FA;font-style:italic;">finish</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Now <code>println!(&quot;{:?}&quot;, config)</code> shows <code>[REDACTED]</code> instead of the actual key.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code reads the API key from the <code>ANTHROPIC_API_KEY</code> environment variable, exactly as you are doing here. It also supports configuration through a JSON config file at <code>~/.claude/config.json</code> for settings that persist across sessions. OpenCode similarly uses environment variables for secrets but stores non-sensitive configuration in a TOML file. The pattern of &quot;secrets in env vars, settings in config files&quot; is universal in production tools.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Never hardcode API keys in source code. Load them from environment variables at runtime and add <code>.env</code> to <code>.gitignore</code>.</li><li>Use <code>dotenvy</code> to load a <code>.env</code> file during development, falling back to actual environment variables in production.</li><li>Centralize configuration in a <code>Config</code> struct with a <code>from_env()</code> constructor that validates required values and provides defaults for optional ones.</li><li>Redact secrets in <code>Debug</code> implementations to prevent accidental logging of API keys.</li><li>Fail fast at startup if required configuration is missing -- a clear error message at launch is far better than a cryptic failure mid-conversation.</li></ul>`,49)])])}const A=n(e,[["render",p]]);export{u as __pageData,A as default};
